    tipo_antecedentes.idDato,
    tipo_antecedentes.estructura,
    antecedentes.valor,
    registros.especialidad
FROM registros
INNER JOIN antecedentes
    ON antecedentes.registro_id = registros.id
INNER JOIN tipo_antecedentes
    ON tipo_antecedentes.id = antecedentes.tipo_antecedente_id
WHERE registros.estado = 0
AND registros.cita = v_idCita
AND registros.especialidad = 1

UNION ALL

