CREATE DEFINER=`root`@`localhost` PROCEDURE `Registros` ()   SELECT
    registros.id,
    registros.cita,
    registros.datos_acompanante,
    consulta.condicion_ingreso,
    consulta.motivo_consulta,
    consulta.enfermedad_actual,
    analisis.analisis,
    analisis.plan_manejo,
    examen_fisico.estado_general,
    examen_fisico.talla,
    examen_fisico.peso,
    examen_fisico.saturacion,
    examen_fisico.frecuencia_cardiaca,
    examen_fisico.frecuencia_respiratoria,
    examen_fisico.temperatura,
    examen_fisico.ocular,
    examen_fisico.verbal,
    examen_fisico.motora,
    examen_fisico.ta_sistolica,
    examen_fisico.ta_diastolica,
    registros.especialidad
FROM registros
INNER JOIN consulta
ON consulta.registro_id = registros.id
INNER JOIN examen_fisico
ON examen_fisico.registro_id = registros.id
INNER JOIN analisis
ON analisis.registro_id = registros.id
WHERE registros.estado = 0
AND registros.especialidad = 1

UNION ALL

SELECT
    registros.id,
    registros.cita,
    registros.datos_acompanante,
    fconsulta.condicion_ingreso,
    fconsulta.motivo_consulta,
    fconsulta.enfermedad_actual,
    fanalisis.analisis,
    fanalisis.plan_manejo,
    fexamen_fisico.estado_general,
    fexamen_fisico.talla,
    fexamen_fisico.peso,
    fexamen_fisico.saturacion,
    fexamen_fisico.frecuencia_cardiaca,
    fexamen_fisico.frecuencia_respiratoria,
    fexamen_fisico.temperatura,
    fexamen_fisico.ocular,
    fexamen_fisico.verbal,
    fexamen_fisico.motora,
    fexamen_fisico.ta_sistolica,
    fexamen_fisico.ta_diastolica,
    registros.especialidad
FROM registros
INNER JOIN fconsulta
ON fconsulta.registro_id = registros.id
INNER JOIN fexamen_fisico
ON fexamen_fisico.registro_id = registros.id
