CREATE DEFINER=`root`@`localhost` PROCEDURE `validarHC` (IN `v_id` INT)   SELECT
registros.id as id,
consulta.id as consulta,
examen_fisico.id as examen,
rips.id as rips,
analisis.id as analisis
FROM registros
LEFT JOIN consulta ON consulta.registro_id = registros.id
LEFT JOIN examen_fisico ON examen_fisico.registro_id = registros.id
LEFT JOIN rips ON rips.registro_id = registros.id
LEFT JOIN analisis ON analisis.registro_id = registros.id
WHERE registros.id = v_id
AND registros.especialidad = 1

UNION ALL

SELECT
registros.id,
fconsulta.id,
fexamen_fisico.id,
frips.id,
fanalisis.id
FROM registros
LEFT JOIN fconsulta ON fconsulta.registro_id = registros.id
LEFT JOIN fexamen_fisico ON fexamen_fisico.registro_id = registros.id
LEFT JOIN frips ON frips.registro_id = registros.id
LEFT JOIN fanalisis ON fanalisis.registro_id = registros.id
WHERE registros.id = v_id
AND registros.especialidad = 2$$

